INSERT INTO cms_page_sections (id, page_id, section_name, section_type, section_data, sort_order, is_visible, created_at, updated_at) VALUES ('sec_agentsam_page_styles', '5de91aa0-10cc-45e5-9607-199d5c2f8467', 'page_styles', 'page_css', '{"html_source": "assembled", "role": "page_css", "css": "/* Agent Sam landing — page styles (shared across sections) */\nmain.agentsam-landing { padding-top: 76px; }\n\n    :root {\n      color-scheme: dark;\n      --bg: #030711;\n      --bg-2: #050b15;\n      --panel: rgba(9, 18, 31, 0.72);\n      --panel-strong: rgba(12, 26, 44, 0.92);\n      --panel-soft: rgba(15, 35, 58, 0.54);\n      --line: rgba(121, 199, 255, 0.17);\n      --line-strong: rgba(121, 199, 255, 0.36);\n      --text: #f1f7ff;\n      --muted: rgba(229, 238, 248, 0.66);\n      --soft: rgba(229, 238, 248, 0.42);\n      --blue: #7fc8ff;\n      --blue-2: #3aa8f8;\n      --cyan: #45e6ff;\n      --green: #b8ff80;\n      --purple: #b68cff;\n      --warn: #ffc766;\n      --danger: #ff7d92;\n      --shadow: 0 32px 90px rgba(0, 0, 0, 0.58);\n      --mono: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, \"Liberation Mono\", \"Courier New\", monospace;\n      --sans: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n      --radius: 28px;\n      --max: 1180px;\n    }\n\n    * { box-sizing: border-box; }\n\n    html {\n      scroll-behavior: smooth;\n      background: var(--bg);\n    }\n\n    body {\n      margin: 0;\n      min-height: 100vh;\n      font-family: var(--sans);\n      color: var(--text);\n      background:\n        radial-gradient(circle at 50% 10%, rgba(86, 170, 255, 0.15), transparent 34rem),\n        radial-gradient(circle at 90% 45%, rgba(57, 171, 255, 0.10), transparent 36rem),\n        linear-gradient(180deg, #020611 0%, #040912 38%, #02060f 100%);\n      overflow-x: hidden;\n    }\n\n    body::before {\n      content: \"\";\n      position: fixed;\n      inset: 0;\n      pointer-events: none;\n      background-image:\n        linear-gradient(rgba(130, 204, 255, 0.035) 1px, transparent 1px),\n        linear-gradient(90deg, rgba(130, 204, 255, 0.035) 1px, transparent 1px);\n      background-size: 88px 88px;\n      mask-image: linear-gradient(180deg, transparent, black 12%, black 86%, transparent);\n      z-index: -2;\n    }\n\n    body::after {\n      content: \"\";\n      position: fixed;\n      inset: 0;\n      pointer-events: none;\n      background: radial-gradient(circle at 50% 0%, transparent 0 24%, rgba(0,0,0,.38) 66%, rgba(0,0,0,.64));\n      z-index: 30;\n      mix-blend-mode: multiply;\n    }\n\n    a { color: inherit; text-decoration: none; }\n\n    button, input, select {\n      font: inherit;\n      color: inherit;\n    }\n\n    .shell {\n      width: min(100%, 100vw);\n      border-inline: 1px solid rgba(135, 203, 255, 0.10);\n    }\n\n\n    .hero {\n      min-height: 860px;\n      position: relative;\n      display: grid;\n      place-items: center;\n      padding: 132px 22px 90px;\n      overflow: hidden;\n      border-bottom: 1px solid rgba(127, 200, 255, 0.12);\n    }\n\n    .hero-grid {\n      position: absolute;\n      left: 0;\n      right: 0;\n      bottom: 70px;\n      height: 280px;\n      opacity: .86;\n      pointer-events: none;\n      background-image: radial-gradient(circle, rgba(107, 182, 238, 0.30) 0 2px, transparent 2.6px);\n      background-size: 24px 24px;\n      mask-image: radial-gradient(ellipse at 34% 45%, black 0 32%, transparent 68%);\n    }\n\n    .hero-lines {\n      position: absolute;\n      width: 1050px;\n      height: 360px;\n      left: 50%;\n      transform: translateX(-16%);\n      bottom: 70px;\n      pointer-events: none;\n      opacity: .75;\n    }\n\n    .hero-orb {\n      position: absolute;\n      left: calc(50% - 17px);\n      bottom: 214px;\n      width: 9px;\n      height: 9px;\n      border-radius: 99px;\n      background: #bde5ff;\n      box-shadow: 0 0 0 1px rgba(255,255,255,.6), 0 0 12px 4px rgba(127,200,255,.6), 0 0 48px 18px rgba(127,200,255,.22);\n      animation: pulse 2.7s ease-in-out infinite;\n    }\n\n    @keyframes pulse {\n      0%, 100% { transform: scale(.9); opacity: .72; }\n      50% { transform: scale(1.22); opacity: 1; }\n    }\n\n    .hero-copy {\n      position: relative;\n      z-index: 2;\n      text-align: center;\n      width: min(980px, 100%);\n      margin-top: -120px;\n    }\n\n    .eyebrow {\n      display: inline-flex;\n      align-items: center;\n      gap: 9px;\n      padding: 9px 12px;\n      border: 1px solid rgba(127, 200, 255, .18);\n      border-radius: 999px;\n      color: rgba(229, 238, 248, .70);\n      background: rgba(5, 14, 25, .52);\n      font-family: var(--mono);\n      font-size: 12px;\n      letter-spacing: .04em;\n      text-transform: uppercase;\n      margin-bottom: 28px;\n    }\n\n    .eyebrow i {\n      width: 8px;\n      height: 8px;\n      border-radius: 99px;\n      display: block;\n      background: var(--blue);\n      box-shadow: 0 0 16px rgba(127,200,255,.86);\n    }\n\n    h1 {\n      margin: 0;\n      font-size: clamp(58px, 10.2vw, 132px);\n      line-height: .88;\n      letter-spacing: -.08em;\n      font-weight: 420;\n      color: transparent;\n      background: linear-gradient(180deg, #a8dcff 0%, #73c2fb 48%, #4c9fe2 100%);\n      -webkit-background-clip: text;\n      background-clip: text;\n      text-wrap: balance;\n      text-shadow: 0 0 54px rgba(77, 167, 238, .10);\n    }\n\n    .hero-copy p {\n      width: min(560px, 92%);\n      margin: 28px auto 0;\n      color: rgba(229, 238, 248, .74);\n      font-size: clamp(17px, 2vw, 22px);\n      line-height: 1.45;\n      text-wrap: balance;\n    }\n\n    .hero-actions {\n      display: flex;\n      justify-content: center;\n      gap: 14px;\n      flex-wrap: wrap;\n      margin-top: 34px;\n    }\n\n    .btn {\n      border: 1px solid rgba(127, 200, 255, .22);\n      border-radius: 8px;\n      height: 52px;\n      padding: 0 24px;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      gap: 10px;\n      font-family: var(--mono);\n      font-size: 14px;\n      letter-spacing: .01em;\n      background: rgba(7, 15, 26, .82);\n      color: rgba(242, 248, 255, .86);\n      box-shadow: inset 0 0 0 1px rgba(255,255,255,.02);\n      cursor: pointer;\n      transition: transform .18s ease, border-color .18s ease, background .18s ease;\n    }\n\n    .btn:hover { transform: translateY(-2px); border-color: rgba(127, 200, 255, .48); background: rgba(15, 31, 52, .84); }\n    .btn-primary { background: #eaf6ff; color: #07111d; border-color: #eaf6ff; }\n    .btn-primary:hover { background: #ffffff; border-color: #ffffff; }\n\n    .orbit-strip {\n      position: absolute;\n      bottom: 22px;\n      left: 50%;\n      transform: translateX(-50%);\n      width: min(960px, calc(100% - 36px));\n      display: grid;\n      grid-template-columns: repeat(4, 1fr);\n      gap: 10px;\n      z-index: 3;\n    }\n\n    .metric {\n      border: 1px solid rgba(127, 200, 255, .13);\n      background: rgba(4, 11, 20, .48);\n      border-radius: 16px;\n      padding: 14px 15px;\n      min-width: 0;\n      backdrop-filter: blur(12px);\n    }\n\n    .metric b {\n      display: block;\n      font-family: var(--mono);\n      font-size: 13px;\n      color: #fff;\n      margin-bottom: 5px;\n    }\n\n    .metric span {\n      display: block;\n      font-size: 12px;\n      color: rgba(229,238,248,.52);\n      white-space: nowrap;\n      overflow: hidden;\n      text-overflow: ellipsis;\n    }\n\n    .story {\n      position: relative;\n      max-width: var(--max);\n      margin: 0 auto;\n    }\n\n    .progress-rail {\n      position: sticky;\n      top: 110px;\n      float: left;\n      width: 138px;\n      margin-left: 12px;\n      height: 360px;\n      display: flex;\n      align-items: flex-start;\n      z-index: 6;\n      pointer-events: none;\n    }\n\n    .rail-line {\n      position: relative;\n      width: 1px;\n      height: 100%;\n      background: linear-gradient(180deg, transparent, rgba(127,200,255,.22) 16%, rgba(127,200,255,.26) 78%, transparent);\n      margin-left: 28px;\n    }\n\n    .rail-dot {\n      position: absolute;\n      left: -4px;\n      top: 44px;\n      width: 9px;\n      height: 9px;\n      border-radius: 99px;\n      background: var(--blue);\n      box-shadow: 0 0 24px rgba(127,200,255,.88);\n      transition: top .38s cubic-bezier(.2,.8,.2,1);\n    }\n\n    .rail-labels {\n      margin-left: 18px;\n      margin-top: 28px;\n      display: grid;\n      gap: 7px;\n      font-family: var(--mono);\n      font-size: 14px;\n      color: rgba(127, 200, 255, .34);\n    }\n\n    .rail-labels span {\n      transition: color .25s ease, transform .25s ease;\n    }\n\n    .rail-labels span.active {\n      color: var(--blue);\n      transform: translateX(2px);\n    }\n\n    .section {\n      position: relative;\n      min-height: 790px;\n      display: grid;\n      grid-template-columns: minmax(280px, 420px) minmax(420px, 1fr);\n      gap: 80px;\n      align-items: center;\n      padding: 120px 20px 120px 230px;\n      border-bottom: 1px solid rgba(127, 200, 255, 0.09);\n    }\n\n    .section::before {\n      content: \"\";\n      position: absolute;\n      inset: 10% -8% 10% 38%;\n      background: radial-gradient(ellipse at center, rgba(92, 174, 255, .11), transparent 62%);\n      opacity: .8;\n      pointer-events: none;\n    }\n\n    .section-copy, .mock-wrap { position: relative; z-index: 2; }\n\n    .section h2 {\n      margin: 0 0 18px;\n      font-size: clamp(34px, 4vw, 52px);\n      line-height: 1.02;\n      letter-spacing: -.055em;\n      font-weight: 460;\n      text-wrap: balance;\n    }\n\n    .section-lead {\n      margin: 0 0 36px;\n      color: var(--muted);\n      font-size: 18px;\n      line-height: 1.45;\n      max-width: 530px;\n    }\n\n    .feature-list {\n      display: grid;\n      gap: 24px;\n    }\n\n    .feature {\n      display: grid;\n      grid-template-columns: 38px 1fr;\n      gap: 18px;\n      align-items: start;\n    }\n\n    .feature svg {\n      width: 28px;\n      height: 28px;\n      stroke: var(--blue);\n      filter: drop-shadow(0 0 18px rgba(127,200,255,.26));\n    }\n\n    .feature h3 {\n      margin: 0 0 8px;\n      font-family: var(--mono);\n      font-size: 19px;\n      line-height: 1.35;\n      font-weight: 430;\n      letter-spacing: .01em;\n    }\n\n    .feature p {\n      margin: 0;\n      color: var(--muted);\n      line-height: 1.5;\n      font-size: 16px;\n    }\n\n    .mock-wrap {\n      min-height: 420px;\n      display: flex;\n      align-items: center;\n      justify-content: center;\n    }\n\n    .mock-card {\n      width: min(650px, 100%);\n      border: 1px solid rgba(127, 200, 255, .23);\n      border-radius: var(--radius);\n      background:\n        linear-gradient(135deg, rgba(7, 16, 28, .90), rgba(17, 45, 72, .70)),\n        radial-gradient(circle at 78% 2%, rgba(127,200,255,.18), transparent 18rem);\n      box-shadow: var(--shadow), inset 0 1px 0 rgba(255,255,255,.04);\n      overflow: hidden;\n      transform: perspective(900px) rotateY(-3deg) rotateX(1deg);\n    }\n\n    .mock-card.wide { width: min(720px, 100%); }\n\n    .mock-top {\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      border-bottom: 1px solid rgba(127, 200, 255, .11);\n      padding: 22px 24px;\n      gap: 16px;\n    }\n\n    .mock-title {\n      font-family: var(--mono);\n      font-size: 15px;\n      color: rgba(242,248,255,.92);\n      letter-spacing: -.01em;\n    }\n\n    .mock-actions {\n      display: flex;\n      align-items: center;\n      gap: 8px;\n      min-width: 0;\n    }\n\n    .chip {\n      border: 1px solid rgba(127, 200, 255, .14);\n      border-radius: 999px;\n      padding: 7px 10px;\n      background: rgba(2, 8, 16, .36);\n      font-family: var(--mono);\n      font-size: 11px;\n      color: rgba(229, 238, 248, .58);\n      white-space: nowrap;\n    }\n\n    .chip.ready {\n      color: rgba(225, 255, 202, .94);\n      border-color: rgba(184,255,128,.22);\n      background: rgba(184,255,128,.07);\n    }\n\n    .chip.purple {\n      color: rgba(224, 205, 255, .94);\n      border-color: rgba(182,140,255,.24);\n      background: rgba(182,140,255,.08);\n    }\n\n    .mock-body { padding: 24px; }\n\n    .usage {\n      display: grid;\n      grid-template-columns: 105px 1fr 44px;\n      gap: 12px;\n      align-items: center;\n      margin-bottom: 26px;\n      font-family: var(--mono);\n      color: rgba(229,238,248,.54);\n      font-size: 12px;\n    }\n\n    .bar {\n      height: 7px;\n      border-radius: 99px;\n      overflow: hidden;\n      background: rgba(127,200,255,.09);\n    }\n\n    .bar span {\n      display: block;\n      height: 100%;\n      border-radius: inherit;\n      background: linear-gradient(90deg, var(--purple), var(--blue));\n      width: 58%;\n      box-shadow: 0 0 20px rgba(182,140,255,.26);\n      animation: breatheWidth 4s ease-in-out infinite;\n    }\n\n    @keyframes breatheWidth {\n      0%, 100% { width: 52%; }\n      50% { width: 76%; }\n    }\n\n    table {\n      width: 100%;\n      border-collapse: collapse;\n      font-family: var(--mono);\n      font-size: 13px;\n      color: rgba(229,238,248,.70);\n    }\n\n    th {\n      text-align: left;\n      color: rgba(229,238,248,.42);\n      text-transform: uppercase;\n      letter-spacing: .08em;\n      font-size: 11px;\n      font-weight: 500;\n      padding: 14px 0;\n      border-bottom: 1px solid rgba(127,200,255,.10);\n    }\n\n    td {\n      padding: 15px 0;\n      border-bottom: 1px solid rgba(127,200,255,.11);\n      white-space: nowrap;\n    }\n\n    td:first-child { color: var(--blue); }\n    .mini-dot { display: inline-block; width: 7px; height: 7px; border-radius: 99px; margin-right: 10px; background: var(--green); box-shadow: 0 0 14px rgba(184,255,128,.75); }\n    .mini-dot.off { background: rgba(229,238,248,.32); box-shadow: none; }\n    .running { color: var(--green); }\n    .pending { color: rgba(229,238,248,.42); }\n\n    .form-grid {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: 14px;\n      font-family: var(--mono);\n    }\n\n    .field {\n      display: grid;\n      gap: 8px;\n    }\n\n    .field.full { grid-column: 1 / -1; }\n\n    .field label {\n      color: rgba(229,238,248,.50);\n      font-size: 12px;\n    }\n\n    .field input, .field select {\n      width: 100%;\n      border: 1px solid rgba(127,200,255,.13);\n      border-radius: 7px;\n      background: rgba(2, 8, 16, .48);\n      min-height: 43px;\n      padding: 0 12px;\n      color: rgba(242,248,255,.84);\n      outline: none;\n    }\n\n    .field input:focus, .field select:focus { border-color: rgba(127,200,255,.45); box-shadow: 0 0 0 3px rgba(127,200,255,.07); }\n\n    .rule-row {\n      display: flex;\n      align-items: center;\n      gap: 10px;\n      border-top: 1px solid rgba(127,200,255,.10);\n      border-bottom: 1px solid rgba(127,200,255,.10);\n      padding: 15px 0;\n      margin-top: 16px;\n      font-family: var(--mono);\n      color: rgba(229,238,248,.52);\n      font-size: 12px;\n    }\n\n    .add-rule {\n      margin-left: auto;\n      height: 31px;\n      padding: 0 13px;\n      border-radius: 7px;\n      border: 1px solid rgba(184,255,128,.20);\n      background: rgba(184,255,128,.07);\n      color: rgba(225,255,202,.92);\n      font-family: var(--mono);\n      cursor: pointer;\n    }\n\n    .terminal-shell {\n      display: grid;\n      grid-template-columns: 180px 1fr;\n      min-height: 440px;\n    }\n\n    .app-rail {\n      padding: 24px 18px;\n      border-right: 1px solid rgba(127,200,255,.10);\n      background: rgba(0,0,0,.14);\n      font-family: var(--mono);\n      font-size: 12px;\n      color: rgba(229,238,248,.42);\n    }\n\n    .app-rail strong {\n      display: block;\n      color: rgba(242,248,255,.86);\n      margin-bottom: 22px;\n      font-family: var(--sans);\n    }\n\n    .rail-menu {\n      display: grid;\n      gap: 11px;\n    }\n\n    .rail-menu span {\n      display: flex;\n      align-items: center;\n      gap: 8px;\n    }\n\n    .rail-menu i {\n      width: 13px;\n      height: 13px;\n      border: 1px solid rgba(127,200,255,.24);\n      border-radius: 4px;\n    }\n\n    .terminal-area { padding: 22px; min-width: 0; }\n\n    .terminal-head {\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      gap: 12px;\n      margin-bottom: 16px;\n    }\n\n    .terminal-head h4 { margin: 0; font-family: var(--mono); font-size: 15px; }\n\n    .terminal-window {\n      border: 1px solid rgba(127,200,255,.13);\n      border-radius: 14px;\n      overflow: hidden;\n      background: rgba(3, 8, 15, .72);\n      font-family: var(--mono);\n      color: rgba(210, 230, 247, .78);\n      font-size: 12px;\n      min-height: 285px;\n    }\n\n    .terminal-tab {\n      padding: 8px 12px;\n      border-bottom: 1px solid rgba(127,200,255,.10);\n      background: rgba(127,200,255,.06);\n      color: rgba(229,238,248,.55);\n    }\n\n    .terminal-output {\n      padding: 15px;\n      line-height: 1.62;\n      min-height: 244px;\n      white-space: pre-wrap;\n    }\n\n    .prompt { color: #ff9bb1; }\n    .command { color: #c2e5ff; }\n    .ok { color: var(--green); }\n    .muted { color: rgba(229,238,248,.36); }\n\n    .agent-grid {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: 14px;\n    }\n\n    .agent-card {\n      border: 1px solid rgba(127,200,255,.13);\n      border-radius: 18px;\n      padding: 16px;\n      background: rgba(3, 10, 18, .40);\n      min-height: 142px;\n      position: relative;\n      overflow: hidden;\n    }\n\n    .agent-card::before {\n      content: \"\";\n      position: absolute;\n      inset: -1px;\n      border-radius: inherit;\n      background: radial-gradient(circle at 20% 0%, rgba(127,200,255,.18), transparent 16rem);\n      pointer-events: none;\n    }\n\n    .agent-card b {\n      position: relative;\n      display: block;\n      font-family: var(--mono);\n      font-size: 14px;\n      margin-bottom: 8px;\n    }\n\n    .agent-card p {\n      position: relative;\n      margin: 0;\n      color: rgba(229,238,248,.57);\n      font-size: 13px;\n      line-height: 1.44;\n    }\n\n    .connector-row {\n      display: flex;\n      gap: 8px;\n      flex-wrap: wrap;\n      margin-top: 16px;\n    }\n\n    .connector-row span {\n      font-family: var(--mono);\n      font-size: 11px;\n      color: rgba(229,238,248,.52);\n      border: 1px solid rgba(127,200,255,.13);\n      border-radius: 999px;\n      padding: 7px 9px;\n      background: rgba(127,200,255,.04);\n    }\n\n    .observe-card .mock-body { display: grid; gap: 14px; }\n\n    .trace-row {\n      display: grid;\n      grid-template-columns: 120px 1fr 72px;\n      align-items: center;\n      gap: 13px;\n      padding: 13px 0;\n      border-bottom: 1px solid rgba(127,200,255,.10);\n      font-family: var(--mono);\n      font-size: 12px;\n    }\n\n    .trace-row:last-child { border-bottom: 0; }\n    .trace-row .name { color: var(--blue); }\n    .trace-row .desc { color: rgba(229,238,248,.58); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n    .trace-row .latency { color: rgba(229,238,248,.42); text-align: right; }\n\n    .mini-progress {\n      position: relative;\n      width: 100%;\n      height: 6px;\n      border-radius: 999px;\n      background: rgba(127,200,255,.08);\n      overflow: hidden;\n      margin: 10px 0 4px;\n    }\n\n    .mini-progress span {\n      display: block;\n      width: 66%;\n      height: 100%;\n      border-radius: inherit;\n      background: linear-gradient(90deg, var(--blue), var(--green));\n      animation: loading 2.6s ease-in-out infinite;\n    }\n\n    @keyframes loading {\n      0%,100% { transform: translateX(-30%); }\n      50% { transform: translateX(35%); }\n    }\n\n    .final {\n      max-width: var(--max);\n      margin: 0 auto;\n      padding: 126px 20px 150px 230px;\n      position: relative;\n    }\n\n    .final-panel {\n      border: 1px solid rgba(127, 200, 255, .16);\n      border-radius: 34px;\n      padding: clamp(28px, 5vw, 64px);\n      background:\n        radial-gradient(circle at 18% 0%, rgba(127,200,255,.17), transparent 28rem),\n        linear-gradient(135deg, rgba(9, 19, 32, .88), rgba(5, 12, 23, .70));\n      box-shadow: var(--shadow);\n      overflow: hidden;\n      position: relative;\n    }\n\n    .final-panel::after {\n      content: \"\";\n      position: absolute;\n      inset: auto -20% -30% 20%;\n      height: 240px;\n      background: radial-gradient(ellipse, rgba(127,200,255,.12), transparent 66%);\n    }\n\n    .final h2 {\n      margin: 0;\n      max-width: 790px;\n      font-size: clamp(42px, 7vw, 86px);\n      line-height: .96;\n      font-weight: 430;\n      letter-spacing: -.065em;\n    }\n\n    .final p {\n      margin: 22px 0 0;\n      color: var(--muted);\n      max-width: 610px;\n      font-size: 18px;\n      line-height: 1.5;\n    }\n\n    .launch-grid {\n      position: relative;\n      z-index: 2;\n      margin-top: 42px;\n      display: grid;\n      grid-template-columns: repeat(4, minmax(0, 1fr));\n      gap: 12px;\n    }\n\n    .launch-step {\n      border: 1px solid rgba(127,200,255,.13);\n      border-radius: 20px;\n      padding: 18px;\n      background: rgba(3, 8, 15, .44);\n      min-height: 142px;\n    }\n\n    .launch-step span {\n      display: inline-flex;\n      width: 31px;\n      height: 31px;\n      border-radius: 12px;\n      align-items: center;\n      justify-content: center;\n      border: 1px solid rgba(127,200,255,.20);\n      color: var(--blue);\n      font-family: var(--mono);\n      margin-bottom: 18px;\n    }\n\n    .launch-step b { display: block; font-family: var(--mono); font-size: 14px; margin-bottom: 8px; }\n    .launch-step small { color: rgba(229,238,248,.54); line-height: 1.45; display: block; }\n\n    .hidden-mobile { display: initial; }\n\n    @media (prefers-reduced-motion: reduce) {\n      html { scroll-behavior: auto; }\n      *, *::before, *::after { animation-duration: 0.001ms !important; animation-iteration-count: 1 !important; transition-duration: 0.001ms !important; }\n    }\n\n    @media (max-width: 1040px) {\n      .section { padding-left: 170px; gap: 44px; grid-template-columns: minmax(260px, 390px) minmax(360px, 1fr); }\n      .final { padding-left: 170px; }\n      .progress-rail { width: 120px; }\n    }\n\n    @media (max-width: 840px) {\n      .nav { height: 56px; top: 10px; }\n      .nav-links { display: none; }\n      .status-pill { font-size: 11px; padding: 9px 10px; }\n      .hero { min-height: 760px; padding-top: 112px; }\n      .hero-copy { margin-top: -140px; }\n      .hero-grid { bottom: 86px; background-size: 20px 20px; }\n      .hero-lines { width: 760px; transform: translateX(-22%); bottom: 84px; opacity: .58; }\n      .hero-orb { bottom: 220px; left: calc(50% - 4px); }\n      .orbit-strip { grid-template-columns: repeat(2, 1fr); bottom: 18px; }\n      .progress-rail {\n        float: none;\n        position: sticky;\n        top: 76px;\n        width: calc(100% - 28px);\n        height: auto;\n        margin: 0 auto;\n        padding: 12px;\n        border: 1px solid rgba(127,200,255,.12);\n        border-radius: 18px;\n        background: rgba(3, 9, 18, .62);\n        backdrop-filter: blur(18px);\n      }\n      .rail-line { display: none; }\n      .rail-labels { margin: 0; grid-template-columns: repeat(4, 1fr); width: 100%; gap: 0; text-align: center; font-size: 12px; }\n      .rail-labels span { padding: 8px 5px; border-radius: 12px; }\n      .rail-labels span.active { background: rgba(127,200,255,.09); transform: none; }\n      .section { min-height: auto; grid-template-columns: 1fr; gap: 34px; padding: 82px 18px; }\n      .section::before { inset: 15% -20% 5% -10%; }\n      .mock-card { transform: none; }\n      .final { padding: 88px 18px 118px; }\n      .launch-grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }\n    }\n\n    @media (max-width: 560px) {\n      .brand-sub { display: none; }\n      .brand-title { font-size: 14px; }\n      .mark { width: 31px; height: 31px; }\n      .status-pill span:last-child { max-width: 96px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }\n      h1 { font-size: clamp(52px, 16.3vw, 72px); line-height: .92; }\n      .hero { min-height: 710px; }\n      .hero-copy p { font-size: 16px; width: 100%; }\n      .hero-actions { gap: 10px; }\n      .btn { width: 100%; height: 50px; }\n      .orbit-strip { display: none; }\n      .hero-grid { height: 240px; mask-image: radial-gradient(ellipse at 50% 50%, black 0 33%, transparent 72%); }\n      .section h2 { font-size: 35px; }\n      .section-lead { font-size: 16px; }\n      .feature { grid-template-columns: 32px 1fr; gap: 13px; }\n      .feature h3 { font-size: 16px; }\n      .feature p { font-size: 14px; }\n      .mock-top { padding: 18px; align-items: flex-start; flex-direction: column; }\n      .mock-body { padding: 18px; }\n      .usage { grid-template-columns: 1fr; gap: 8px; }\n      table { font-size: 11px; }\n      th:nth-child(2), td:nth-child(2) { display: none; }\n      .form-grid { grid-template-columns: 1fr; }\n      .terminal-shell { grid-template-columns: 1fr; }\n      .app-rail { display: none; }\n      .agent-grid { grid-template-columns: 1fr; }\n      .trace-row { grid-template-columns: 90px 1fr; }\n      .trace-row .latency { display: none; }\n      .launch-grid { grid-template-columns: 1fr; }\n    }\n  "}', 5, 1, unixepoch(), unixepoch());
INSERT INTO cms_page_sections (id, page_id, section_name, section_type, section_data, sort_order, is_visible, created_at, updated_at) VALUES ('sec_agentsam_hero', '5de91aa0-10cc-45e5-9607-199d5c2f8467', 'hero', 'hero', '{"html_source": "assembled", "html": "<section class=\"hero\" data-section-key=\"hero\" data-cms-section=\"hero\" data-section-type=\"hero\" aria-labelledby=\"hero-title\">\n        <div class=\"hero-grid\" aria-hidden=\"true\"></div>\n        <svg class=\"hero-lines\" viewBox=\"0 0 1050 360\" aria-hidden=\"true\" preserveAspectRatio=\"none\">\n          <defs>\n            <linearGradient id=\"lineFade\" x1=\"0\" x2=\"1\">\n              <stop offset=\"0\" stop-color=\"#7fc8ff\" stop-opacity=\"0.02\" />\n              <stop offset=\"0.36\" stop-color=\"#7fc8ff\" stop-opacity=\"0.48\" />\n              <stop offset=\"0.78\" stop-color=\"#1a94df\" stop-opacity=\"0.22\" />\n              <stop offset=\"1\" stop-color=\"#1a94df\" stop-opacity=\"0\" />\n            </linearGradient>\n          </defs>\n          <path d=\"M 50 36 C 172 150, 264 165, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 74 C 164 150, 250 165, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 112 C 154 154, 248 168, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 150 C 156 168, 248 176, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 180 C 162 180, 251 180, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 210 C 162 190, 251 184, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 248 C 164 206, 250 191, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 286 C 172 210, 264 195, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n        </svg>\n        <div class=\"hero-orb\" aria-hidden=\"true\"></div>\n        <div class=\"hero-copy\">\n          <div class=\"eyebrow\"><i aria-hidden=\"true\"></i> Cloud contained sandbox layer</div>\n          <h1 id=\"hero-title\">Give AgentSam a secure computer</h1>\n          <p>Ephemeral, isolated sandboxes for agent-generated code, tool calls, terminals, previews, and long-running build sessions.</p>\n          <div class=\"hero-actions\">\n            <a class=\"btn btn-primary\" href=\"#secure\">Start building</a>\n            <a class=\"btn\" href=\"#observe\">View the control plane</a>\n          </div>\n        </div>\n        <div class=\"orbit-strip\" aria-label=\"Capability metrics\">\n          <div class=\"metric\"><b>Ephemeral by default</b><span>fresh compute for risky tasks</span></div>\n          <div class=\"metric\"><b>Tool-aware access</b><span>credentials proxied, never leaked</span></div>\n          <div class=\"metric\"><b>Parallel workers</b><span>fan out builds, tests, audits</span></div>\n          <div class=\"metric\"><b>Persistent sessions</b><span>snapshots, logs, tunnels, TTLs</span></div>\n        </div>\n      </section>", "r2_key": "pages/agentsam/sections/hero.html"}', 10, 1, unixepoch(), unixepoch());
INSERT INTO cms_page_sections (id, page_id, section_name, section_type, section_data, sort_order, is_visible, created_at, updated_at) VALUES ('sec_agentsam_story_chrome', '5de91aa0-10cc-45e5-9607-199d5c2f8467', 'story_chrome', 'story_chrome', '{"html_source": "assembled", "role": "story_chrome", "html": "<aside class=\"progress-rail\" aria-label=\"Capability section progress\">\n          <div class=\"rail-line\"><span class=\"rail-dot\" id=\"railDot\" aria-hidden=\"true\"></span></div>\n          <div class=\"rail-labels\">\n            <span data-rail=\"secure\" class=\"active\">Secure</span>\n            <span data-rail=\"scale\">Scalable</span>\n            <span data-rail=\"state\">Stateful</span>\n            <span data-rail=\"observe\">Observable</span>\n          </div>\n        </aside>"}', 15, 1, unixepoch(), unixepoch());
INSERT INTO cms_page_sections (id, page_id, section_name, section_type, section_data, sort_order, is_visible, created_at, updated_at) VALUES ('sec_agentsam_secure', '5de91aa0-10cc-45e5-9607-199d5c2f8467', 'secure', 'feature_split', '{"html_source": "assembled", "html": "<section class=\"section\" id=\"secure\" data-section-key=\"secure\" data-cms-section=\"secure\" data-section=\"secure\" aria-labelledby=\"secure-title\">\n          <div class=\"section-copy\">\n            <h2 id=\"secure-title\">Run untrusted code safely</h2>\n            <p class=\"section-lead\">AgentSam can explore packages, run commands, inspect files, and execute generated code without touching your core app infrastructure.</p>\n            <div class=\"feature-list\">\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"M12 3 20 6v6c0 5-3.4 7.7-8 9-4.6-1.3-8-4-8-9V6l8-3Z\"/><path d=\"m9 12 2 2 4-5\"/></svg>\n                <div><h3>MicroVM isolation</h3><p>Every risky action runs in a dedicated cloud sandbox instead of your live dashboard, repo, or customer system.</p></div>\n              </article>\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><rect x=\"5\" y=\"10\" width=\"14\" height=\"10\" rx=\"2\"/><path d=\"M8 10V7a4 4 0 0 1 8 0v3\"/><path d=\"M12 14v2\"/></svg>\n                <div><h3>Auth proxy for credentials</h3><p>Secrets stay behind policy. Agents receive scoped access to only the services, files, and routes that task requires.</p></div>\n              </article>\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"M4 6h16\"/><path d=\"M7 12h10\"/><path d=\"M10 18h4\"/><path d=\"M4 6c2 0 3 6 8 6s6-6 8-6\"/><path d=\"M7 12c1.4 0 2.2 6 5 6s3.6-6 5-6\"/></svg>\n                <div><h3>Clean blast-radius boundaries</h3><p>Sandbox file systems, environment variables, package installs, and generated assets are disposable unless promoted.</p></div>\n              </article>\n            </div>\n          </div>\n\n          <div class=\"mock-wrap\">\n            <article class=\"mock-card wide\" aria-label=\"Sandbox fleet mockup\">\n              <div class=\"mock-top\">\n                <div class=\"mock-title\">AgentSam / Sandboxes</div>\n                <div class=\"mock-actions\">\n                  <span class=\"chip ready\">policy: locked</span>\n                  <span class=\"chip\">root isolated</span>\n                </div>\n              </div>\n              <div class=\"mock-body\">\n                <div class=\"usage\">\n                  <span>Resource usage</span>\n                  <div class=\"bar\" aria-hidden=\"true\"><span></span></div>\n                  <span>CPU</span>\n                </div>\n                <table aria-label=\"Running sandboxes\">\n                  <thead><tr><th>Sandbox</th><th>Started</th><th>Status</th></tr></thead>\n                  <tbody>\n                    <tr><td><span class=\"mini-dot\"></span>sandbox-4f7eb1</td><td>runs agent-5</td><td class=\"running\">running</td></tr>\n                    <tr><td><span class=\"mini-dot\"></span>sandbox-b72da4</td><td>runs agent-8</td><td class=\"running\">running</td></tr>\n                    <tr><td><span class=\"mini-dot\"></span>sandbox-193af0</td><td>runs agent-2</td><td class=\"running\">running</td></tr>\n                    <tr><td><span class=\"mini-dot off\"></span>sandbox-567cbb</td><td>—</td><td class=\"pending\">start soon</td></tr>\n                  </tbody>\n                </table>\n              </div>\n            </article>\n          </div>\n        </section>", "r2_key": "pages/agentsam/sections/secure.html"}', 20, 1, unixepoch(), unixepoch());
INSERT INTO cms_page_sections (id, page_id, section_name, section_type, section_data, sort_order, is_visible, created_at, updated_at) VALUES ('sec_agentsam_scale', '5de91aa0-10cc-45e5-9607-199d5c2f8467', 'scale', 'feature_split', '{"html_source": "assembled", "html": "<section class=\"section\" id=\"scale\" data-section-key=\"scale\" data-cms-section=\"scale\" data-section=\"scale\" aria-labelledby=\"scale-title\">\n          <div class=\"section-copy\">\n            <h2 id=\"scale-title\">Sub-second starts for agent fleets</h2>\n            <p class=\"section-lead\">Prewarmed pools make sandbox launch feel instant, so AgentSam can branch work across code generation, tests, browser research, and repo inspection.</p>\n            <div class=\"feature-list\">\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"m13 2-9 12h7l-1 8 10-13h-7l1-7Z\"/></svg>\n                <div><h3>Burst to thousands on demand</h3><p>Fan out audits, evals, migrations, and build attempts without tying up a single terminal session.</p></div>\n              </article>\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"m12 3 8 4.5v9L12 21l-8-4.5v-9L12 3Z\"/><path d=\"M12 12 4 7.5\"/><path d=\"M12 12v9\"/><path d=\"m12 12 8-4.5\"/></svg>\n                <div><h3>Bring your own image</h3><p>Pin CPU, memory, packages, browsers, CAD tooling, Node, Python, ffmpeg, or repo-specific dependencies.</p></div>\n              </article>\n            </div>\n          </div>\n\n          <div class=\"mock-wrap\">\n            <article class=\"mock-card\" aria-label=\"Create sandbox mockup\">\n              <div class=\"mock-top\">\n                <div class=\"mock-title\">Create Sandbox</div>\n                <span class=\"chip purple\">prewarmed pool</span>\n              </div>\n              <div class=\"mock-body\">\n                <div class=\"form-grid\">\n                  <div class=\"field full\"><label>Snapshot</label><input value=\"agentsam-node-22-python-3.12\" aria-label=\"Snapshot\" /></div>\n                  <div class=\"field\"><label>vCPUs</label><input value=\"4\" aria-label=\"vCPUs\" /></div>\n                  <div class=\"field\"><label>Memory (MiB)</label><input value=\"4096\" aria-label=\"Memory\" /></div>\n                  <div class=\"field full\"><label>Name</label><input value=\"repo-audit--inneranimalmedia\" aria-label=\"Name\" /></div>\n                  <div class=\"field\"><label>TTL</label><input value=\"60 min\" aria-label=\"TTL\" /></div>\n                  <div class=\"field\"><label>Idle TTL</label><input value=\"8 min\" aria-label=\"Idle TTL\" /></div>\n                </div>\n                <div class=\"rule-row\">\n                  <span>Proxy Rules</span>\n                  <button class=\"add-rule\" type=\"button\">+ Add Rule</button>\n                </div>\n                <div class=\"field\"><label>Access Control</label><select aria-label=\"Access control\"><option>AgentSam scoped tools only</option><option>Read-only filesystem</option><option>No external network</option></select></div>\n              </div>\n            </article>\n          </div>\n        </section>", "r2_key": "pages/agentsam/sections/scale.html"}', 30, 1, unixepoch(), unixepoch());
INSERT INTO cms_page_sections (id, page_id, section_name, section_type, section_data, sort_order, is_visible, created_at, updated_at) VALUES ('sec_agentsam_state', '5de91aa0-10cc-45e5-9607-199d5c2f8467', 'state', 'feature_split', '{"html_source": "assembled", "html": "<section class=\"section\" id=\"state\" data-section-key=\"state\" data-cms-section=\"state\" data-section=\"state\" aria-labelledby=\"state-title\">\n          <div class=\"section-copy\">\n            <h2 id=\"state-title\">Built for long-running, stateful work</h2>\n            <p class=\"section-lead\">Sessions stream over WebSockets, retain state across threads, and stay alive only as long as the job needs.</p>\n            <div class=\"feature-list\">\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"M6 3h12\"/><path d=\"M6 21h12\"/><path d=\"M8 3c0 5 8 5 8 9s-8 4-8 9\"/><path d=\"M16 3c0 5-8 5-8 9s8 4 8 9\"/></svg>\n                <div><h3>Configurable TTLs</h3><p>Expire idle sessions automatically, cap total runtime, and keep build experiments from becoming surprise infrastructure.</p></div>\n              </article>\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"M6 3v18\"/><path d=\"M18 6v12\"/><circle cx=\"6\" cy=\"6\" r=\"2\"/><circle cx=\"18\" cy=\"18\" r=\"2\"/><path d=\"M6 8c0 4 12 2 12 8\"/></svg>\n                <div><h3>Snapshot and fork</h3><p>Capture a running sandbox, restore it later, or branch alternatives so agents can explore safely in parallel.</p></div>\n              </article>\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"M4 8h10a4 4 0 0 1 0 8H9\"/><path d=\"m7 12-3-4 3-4\"/><path d=\"M20 16H10a4 4 0 0 1 0-8h5\"/><path d=\"m17 12 3 4-3 4\"/></svg>\n                <div><h3>Port tunneling</h3><p>Preview a running app, API endpoint, model viewer, CAD job, or static build without exposing the whole machine.</p></div>\n              </article>\n            </div>\n          </div>\n\n          <div class=\"mock-wrap\">\n            <article class=\"mock-card wide\" aria-label=\"Live terminal mockup\">\n              <div class=\"terminal-shell\">\n                <aside class=\"app-rail\">\n                  <strong>AgentSam</strong>\n                  <div class=\"rail-menu\">\n                    <span><i></i> All applications</span>\n                    <span><i></i> Search</span>\n                    <span><i></i> Home</span>\n                    <span><i></i> Tracing</span>\n                    <span><i></i> Monitoring</span>\n                    <span><i></i> Datasets &amp; evals</span>\n                    <span><i></i> Prompts</span>\n                    <span><i></i> Studio</span>\n                  </div>\n                </aside>\n                <div class=\"terminal-area\">\n                  <div class=\"terminal-head\">\n                    <h4>sandbox-8530bec8</h4>\n                    <div class=\"mock-actions\"><span class=\"chip ready\">READY</span><span class=\"chip purple\">Open tunnel</span></div>\n                  </div>\n                  <div class=\"terminal-window\">\n                    <div class=\"terminal-tab\">Terminal</div>\n                    <pre class=\"terminal-output\" id=\"terminalOutput\"><span class=\"prompt\">root@agentsam:~#</span> <span class=\"command\">uname &amp;&amp; node -v</span>\nLinux\nv22.11.0\n<span class=\"prompt\">root@agentsam:~#</span> <span class=\"command\">npm test -- --runInBand</span>\n<span class=\"ok\">✓</span> auth proxy policy validated\n<span class=\"ok\">✓</span> worker bindings mocked\n<span class=\"ok\">✓</span> preview tunnel listening on :8787\n<span class=\"muted\">streaming logs to AgentSam control plane...</span></pre>\n                  </div>\n                </div>\n              </div>\n            </article>\n          </div>\n        </section>", "r2_key": "pages/agentsam/sections/state.html"}', 40, 1, unixepoch(), unixepoch());
INSERT INTO cms_page_sections (id, page_id, section_name, section_type, section_data, sort_order, is_visible, created_at, updated_at) VALUES ('sec_agentsam_observe', '5de91aa0-10cc-45e5-9607-199d5c2f8467', 'observe', 'feature_split', '{"html_source": "assembled", "html": "<section class=\"section\" id=\"observe\" data-section-key=\"observe\" data-cms-section=\"observe\" data-section=\"observe\" aria-labelledby=\"observe-title\">\n          <div class=\"section-copy\">\n            <h2 id=\"observe-title\">Observe every agent run before it ships</h2>\n            <p class=\"section-lead\">AgentSam needs more than a terminal. It needs traces, approvals, cost controls, logs, artifacts, and a clear path from experiment to production.</p>\n            <div class=\"feature-list\">\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"M3 12h4l3 8 4-16 3 8h4\"/></svg>\n                <div><h3>Trace the decision path</h3><p>See which model, tool, repo, file, command, and sandbox produced each result.</p></div>\n              </article>\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"M12 3v18\"/><path d=\"M5 8h14\"/><path d=\"M7 16h10\"/><path d=\"M8 8l-3 8\"/><path d=\"M16 8l3 8\"/></svg>\n                <div><h3>Human approval gates</h3><p>Let agents build aggressively, then require review before deploys, credential use, data writes, or billing-impacting actions.</p></div>\n              </article>\n            </div>\n          </div>\n\n          <div class=\"mock-wrap\">\n            <article class=\"mock-card observe-card\" aria-label=\"Agent run observability mockup\">\n              <div class=\"mock-top\">\n                <div class=\"mock-title\">Control Plane / agent-run-9074</div>\n                <div class=\"mock-actions\"><span class=\"chip ready\">approved</span><span class=\"chip\">cost: $0.31</span></div>\n              </div>\n              <div class=\"mock-body\">\n                <div class=\"agent-grid\">\n                  <div class=\"agent-card\"><b>Planner</b><p>Reads the issue, creates a safe task graph, and asks for sandboxed execution.</p><div class=\"mini-progress\"><span></span></div></div>\n                  <div class=\"agent-card\"><b>Builder</b><p>Runs code, installs packages, executes tests, and returns only promoted artifacts.</p><div class=\"connector-row\"><span>GitHub</span><span>D1</span><span>R2</span></div></div>\n                  <div class=\"agent-card\"><b>Browser</b><p>Opens tunnel previews, captures screenshots, and reports UI regressions.</p><div class=\"connector-row\"><span>Preview</span><span>Screenshot</span></div></div>\n                  <div class=\"agent-card\"><b>Reviewer</b><p>Summarizes diffs, commands, logs, failures, risk, and what changed.</p><div class=\"connector-row\"><span>Diff</span><span>Logs</span><span>Approval</span></div></div>\n                </div>\n                <div>\n                  <div class=\"trace-row\"><span class=\"name\">spawn</span><span class=\"desc\">sandbox-8530bec8 from repo image</span><span class=\"latency\">184ms</span></div>\n                  <div class=\"trace-row\"><span class=\"name\">execute</span><span class=\"desc\">npm test, wrangler dry-run, static preview</span><span class=\"latency\">31.4s</span></div>\n                  <div class=\"trace-row\"><span class=\"name\">promote</span><span class=\"desc\">artifact bundle + review summary ready</span><span class=\"latency\">2.1s</span></div>\n                </div>\n              </div>\n            </article>\n          </div>\n        </section>", "r2_key": "pages/agentsam/sections/observe.html"}', 50, 1, unixepoch(), unixepoch());
INSERT INTO cms_page_sections (id, page_id, section_name, section_type, section_data, sort_order, is_visible, created_at, updated_at) VALUES ('sec_agentsam_cta', '5de91aa0-10cc-45e5-9607-199d5c2f8467', 'cta', 'cta_banner', '{"html_source": "assembled", "html": "<section class=\"final\" data-section-key=\"cta\" data-cms-section=\"cta\" data-section-type=\"cta_banner\" aria-labelledby=\"final-title\">\n        <div class=\"final-panel\">\n          <div class=\"eyebrow\"><i aria-hidden=\"true\"></i> AgentSam operating layer</div>\n          <h2 id=\"final-title\">Let the agent work hard without giving it your whole system.</h2>\n          <p>This page frames the product story: AgentSam gets a disposable computer, scoped tools, observable execution, and a clean promotion path back into your real Cloudflare, Supabase, GitHub, Gmail, Drive, and design workflows.</p>\n          <div class=\"launch-grid\" aria-label=\"Sandbox run lifecycle\">\n            <article class=\"launch-step\"><span>01</span><b>Plan</b><small>AgentSam defines the task, needed tools, limits, and approval gates.</small></article>\n            <article class=\"launch-step\"><span>02</span><b>Contain</b><small>A fresh sandbox starts with scoped credentials and task-specific policy.</small></article>\n            <article class=\"launch-step\"><span>03</span><b>Execute</b><small>Code, terminals, previews, tests, and generated assets stay isolated.</small></article>\n            <article class=\"launch-step\"><span>04</span><b>Promote</b><small>Only reviewed files, logs, patches, and artifacts move into production.</small></article>\n          </div>\n          <div class=\"hero-actions\" style=\"justify-content:flex-start; position:relative; z-index:2;\">\n            <a class=\"btn btn-primary\" href=\"#top\">Back to top</a>\n            <button class=\"btn\" type=\"button\" id=\"copyBrief\">Copy capability brief</button>\n          </div>\n        </div>\n      </section>", "r2_key": "pages/agentsam/sections/cta.html"}', 60, 1, unixepoch(), unixepoch());
INSERT INTO cms_page_sections (id, page_id, section_name, section_type, section_data, sort_order, is_visible, created_at, updated_at) VALUES ('sec_agentsam_page_scripts', '5de91aa0-10cc-45e5-9607-199d5c2f8467', 'page_scripts', 'page_js', '{"html_source": "assembled", "role": "page_js", "js": "const sections = [...document.querySelectorAll(''[data-section]'')];\n    const labels = [...document.querySelectorAll(''[data-rail]'')];\n    const railDot = document.getElementById(''railDot'');\n\n    const setActive = (id) => {\n      labels.forEach((label, index) => {\n        const active = label.dataset.rail === id;\n        label.classList.toggle(''active'', active);\n        if (active && railDot) railDot.style.top = `${44 + index * 31}px`;\n      });\n    };\n\n    const observer = new IntersectionObserver((entries) => {\n      const visible = entries\n        .filter(entry => entry.isIntersecting)\n        .sort((a, b) => b.intersectionRatio - a.intersectionRatio)[0];\n      if (visible) setActive(visible.target.dataset.section);\n    }, { rootMargin: ''-28% 0px -45% 0px'', threshold: [0.12, 0.24, 0.42] });\n\n    sections.forEach(section => observer.observe(section));\n\n    const copyButton = document.getElementById(''copyBrief'');\n    copyButton?.addEventListener(''click'', async () => {\n      const brief = `AgentSam Cloud Contained Sandbox Capabilities\\n\\nGive agents a secure computer: ephemeral isolated sandboxes for agent-generated code, terminals, previews, tests, and long-running build sessions. Core story: contain untrusted work, proxy credentials through policy, scale parallel agent fleets, preserve state with TTLs/snapshots/tunnels, observe every command and artifact, then promote only reviewed output back to production.`;\n      try {\n        await navigator.clipboard.writeText(brief);\n        copyButton.textContent = ''Copied brief'';\n        setTimeout(() => copyButton.textContent = ''Copy capability brief'', 1600);\n      } catch (error) {\n        copyButton.textContent = ''Brief ready'';\n      }\n    });\n"}', 95, 1, unixepoch(), unixepoch());
